    for (const [x, y] of points) {
        if (!yMap.has(y)) {
            yMap.set(y, []);
        }
        yMap.get(y).push(x);
    }

    // Count the number of points for each y-coordinate
    for (const [y, xs] of yMap.entries()) {
        yCount.set(y, xs.length);
    }

    let result = 0;

    // Iterate through all pairs of y-coordinates
    for (const [y1, xs1] of yMap.entries()) {
        for (const [y2, xs2] of yMap.entries()) {
            if (y1 === y2) continue;

            // Calculate the number of horizontal lines between y1 and y2
            const count = Math.min(yCount.get(y1), yCount.get(y2));

            // For each horizontal line, calculate the number of trapezoids
            // that can be formed with this line and another line at y2
            // The formula is C(n, 2) * C(m, 2) where n is the number of points at y1 and m at y2
            // But since we are considering pairs of horizontal lines, we need to multiply by the number of ways to choose 2 points from each line
            const ways = (count * (count - 1) / 2) * (yCount.get(y1) * (yCount.get(y1) - 1) / 2) * (yCount.get(y2) * (yCount.get(y2) - 1) / 2);
            result = (result + ways) % MOD;
        }
    }

    return result;
